import React, { Component } from "react";
import ReactDOM from "react-dom";

class Creator extends Component {

    constructor(props) {
        super(props)
        this.state = {
            innerHTML: (
                <div>ghbdtn</div>,
                <div>sdfsdf</div>
            )
        }
    }

    render() {
        return (
            <>
                { this.state.innerHTML }
            </>
        )
    }
}

ReactDOM.render(
    <Creator />,
    document.querySelector('#App')
)
